script:
export const meta = {
  name: 'cleanup_tus',
  description: 'Apply R1-R8 cleanup to one or more FULL_MATCH translation units',
}

const tuList = (args && args.tus) || []
const onlyComments = (args && args.onlyComments) || false

log('tuList length: ' + tuList.length)
if (tuList.length > 0) {
  log('first unit: ' + tuList[0].unit)
}

if (!tuList.length) {
  log('No TUs provided in args.tus')
  return { status: 'skipped', reason: 'no tus' }
}

log('Cleaning ' + tuList.length + ' TUs (onlyComments=' + onlyComments + ')')

const tasks = tuList.map(t => () => {
  const unit = t.unit
  const file = t.file
  const desc = (t.desc || '')
  log('Starting agent for: ' + unit)
  return agent(
    (onlyComments
      ? 'Add R8 comments to FULL_MATCH TU: ' + unit + '\n\nSource: ' + file + '\n\nFOCUS ON R8 ONLY. Do NOT change any code or field names.\n- Add leading comment blocks to functions 10+ lines (what, why, params, return)\n- Add inline comments to non-obvious fields, magic constants, linker symbols\n- Small helpers/trivial wrappers skip comments\n- R7: verify build+diff+size after edits, no regressions\n\n' + desc
      : 'Clean up FULL_MATCH TU: ' + unit + '\n\nSource: ' + file + '\n\nApply ALL rules (R1-R8) to ALL FULL_MATCH functions:\n- R1: NO void pointers\n- R2: NO pointer arithmetic\n- R3: NO void types\n- R4: Proper classes/structs\n- R5: Human-friendly names for fields, vars, params\n- R6: Create headers if missing\n- R7: Never regress \u2014 build+diff+size after EVERY edit\n- R8: Comments on functions 10+ lines and non-obvious fields\n\n' + desc),
    { agent: 'cleanup', agentScope: 'both', confirmProjectAgents: false }
  )
})

log('Calling parallel with ' + tasks.length + ' tasks')
const results = await parallel(tasks)
log('Parallel returned, results: ' + (results ? results.length : 'null'))

return { processed: tuList.length, results: results || [] }
